class QuietThreadingHTTPServer(ThreadingHTTPServer):
    """Do not dump harmless browser disconnects into a 24/7 operator log."""

    def handle_error(self, request, client_address):
        error = sys.exc_info()[1]
        if isinstance(error, (BrokenPipeError, ConnectionAbortedError, ConnectionResetError)):
            return
        super().handle_error(request, client_address)


class OverlayServer:
    def __init__(self, game, host="127.0.0.1", port=8765, background="#071c13", accent="#e6b94a", font="Arial, sans-serif", layout="horizontal", reduced_motion=False, audio_enabled=False, disclaimer_enabled=True, director_enabled=True, rotation_enabled=True, rotation_interval_ms=9000, narration_enabled=False, showrunner_enabled=True, voice_cues_enabled=True, voice_cooldown_ms=9000, non_reader_mode=True, night_city_intensity="high", venue_theme_enabled=True, recap_duration_ms=7500, moment_duration_ms=6200, visual_debug=False, music_dir="music", music_enabled=True, sound_effects_dir="sound_effects", voice_service=None):
        self.game = game
        self.host = host
        self.port = port
        self.background = background if re.fullmatch(r"#[0-9a-fA-F]{3,8}", background) else "#071c13"
        self.accent = accent if re.fullmatch(r"#[0-9a-fA-F]{3,8}", accent) else "#e6b94a"
        self.font = re.sub(r"[{};<>\r\n]", "", font) or "Arial, sans-serif"
        self.layout = layout if layout in {"horizontal", "vertical"} else "horizontal"
        self.reduced_motion = bool(reduced_motion)
        self.audio_enabled = bool(audio_enabled)
        self.disclaimer_enabled = bool(disclaimer_enabled)
        self.director_enabled = bool(director_enabled)
        self.rotation_enabled = bool(rotation_enabled)
        self.rotation_interval_ms = max(5000, int(rotation_interval_ms))
        self.narration_enabled = bool(narration_enabled)
        self.showrunner_enabled = bool(showrunner_enabled)
        self.voice_cues_enabled = bool(voice_cues_enabled)
        self.voice_cooldown_ms = max(3000, int(voice_cooldown_ms or 9000))
        self.non_reader_mode = bool(non_reader_mode)
        self.night_city_intensity = night_city_intensity if night_city_intensity in {"low", "medium", "high"} else "high"
        self.venue_theme_enabled = bool(venue_theme_enabled)
        self.recap_duration_ms = max(1200, int(recap_duration_ms))
        self.moment_duration_ms = max(1200, int(moment_duration_ms))
        self.visual_debug = bool(visual_debug)
        self.music_dir = Path(music_dir)
        self.music_enabled = bool(music_enabled)
        self.music_tracks = self._discover_music_tracks()
        self.sound_effects_dir = Path(sound_effects_dir)
        self.sound_effects = self._discover_sound_effects()
        self.voice_service = voice_service
        self._server = None
        self._thread = None
        self._closing = False
        self._sse_slots = BoundedSemaphore(8)

    def start(self):
        outer = self

        class Handler(BaseHTTPRequestHandler):
            protocol_version = "HTTP/1.1"

            def do_GET(self):
                parsed = urlparse(self.path)
                path = parsed.path
                if path == "/state":
                    self._send_json(outer.state_snapshot())
                elif path == "/events":
                    self._send_events(parse_qs(parsed.query))
                elif path in ("/", "/overlay"):
                    query = parse_qs(parsed.query)
                    audio_on = outer._query_enabled(query, "audio", outer.audio_enabled)
                    music_on = audio_on and outer._query_enabled(query, "music", outer.music_enabled and bool(outer.music_tracks))
                    director_on = outer._query_enabled(query, "director", outer.director_enabled)
                    visual_debug = outer._query_enabled(query, "visual_debug", outer.visual_debug)
                    music_tracks = [f"/music/{index}.wav" for index, _track in enumerate(outer.music_tracks)] if music_on else []
                    effects = outer.sound_effect_urls() if audio_on else {}
                    page = (OVERLAY_HTML.replace("__BACKGROUND__", outer.background).replace("__ACCENT__", outer.accent).replace("__FONT__", outer.font).replace("__LAYOUT__", outer.layout).replace("__REDUCED__", "reduced" if outer.reduced_motion else "").replace("__AUDIO__", "audio-on" if audio_on else "").replace("__MUSIC__", "on" if music_on else "off").replace("__DIRECTOR__", "on" if director_on else "off").replace("__ROTATION__", "on" if outer.rotation_enabled else "off").replace("__ROTATION_MS__", str(outer.rotation_interval_ms)).replace("__NARRATION__", "on" if outer.narration_enabled else "off").replace("__SHOWRUNNER__", "on" if outer.showrunner_enabled else "off").replace("__VOICE_CUES__", "on" if outer.voice_cues_enabled else "off").replace("__VOICE_COOLDOWN__", str(outer.voice_cooldown_ms)).replace("__NON_READER__", "on" if outer.non_reader_mode else "off").replace("__NIGHT_CITY_INTENSITY__", outer.night_city_intensity).replace("__VENUE_THEME__", "on" if outer.venue_theme_enabled else "off").replace("__VISUAL_DEBUG__", "on" if visual_debug else "off").replace("__RECAP_DURATION__", str(outer.recap_duration_ms)).replace("__MOMENT_DURATION__", str(outer.moment_duration_ms)).replace("__MUSIC_TRACKS__", json.dumps(music_tracks)).replace("__SOUND_EFFECTS__", json.dumps(effects)).replace("__DISCLAIMER_CLASS__", "" if outer.disclaimer_enabled else "hidden"))
                    self._send(200, "text/html; charset=utf-8", page.encode("utf-8"))
                elif path == "/health":
                    state = outer.game.state_snapshot()
                    self._send_json({"status": "ok" if state["health"]["overall"] != "warning" else "warning", "schema_version": 2, "event_sequence": state["event_sequence"], "health": state["health"]})
                elif path == "/stream-info":
                    self._send_json(outer.stream_info())
                elif path.startswith("/music/"):
                    self._send_music(path)
                elif path.startswith("/sound/"):
                    self._send_sound(path)
                elif path.startswith("/voice/"):
                    self._send_voice(path)
                else:
                    self._send_json({"error": "not found"}, status=404)

            def _send_events(self, query):
                if not outer._sse_slots.acquire(blocking=False):
                    self._send_json({"error": "event client limit reached"}, status=503)
                    return
                self.close_connection = True
                try:
                    try:
                        sequence = int(self.headers.get("Last-Event-ID") or query.get("since", [0])[0])
                    except ValueError:
                        sequence = 0
                    self.send_response(200)
                    self.send_header("Content-Type", "text/event-stream; charset=utf-8")
                    self.send_header("Cache-Control", "no-cache")
                    self.send_header("Connection", "keep-alive")
                    self.send_header("Access-Control-Allow-Origin", "*")
                    self.end_headers()
                    deadline = time.monotonic() + 25
                    try:
                        while not outer._closing and time.monotonic() < deadline:
                            events = outer.game.wait_for_events(sequence, timeout=8)
                            if not events:
                                self.wfile.write(b": keepalive\n\n")
                                self.wfile.flush()
                                continue
                            for event in events:
                                sequence = event["id"]
                                body = json.dumps(event, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
                                self.wfile.write(f"id: {sequence}\ndata: ".encode("utf-8") + body + b"\n\n")
                            self.wfile.flush()
                    except (BrokenPipeError, ConnectionResetError, OSError):
                        return
                finally:
                    outer._sse_slots.release()

            def _send_json(self, value, status=200):
                self._send(status, "application/json; charset=utf-8", json.dumps(value).encode("utf-8"))

            def _send(self, status, content_type, body):
                self.send_response(status)
                self.send_header("Content-Type", content_type)
                self.send_header("Content-Length", str(len(body)))
                self.send_header("Cache-Control", "no-store")
                self.send_header("Access-Control-Allow-Origin", "*")
                self.end_headers()
                self.wfile.write(body)

            def _send_music(self, path):
                match = re.fullmatch(r"/music/([0-9]+)\.wav", path)
                if not match:
                    self._send_json({"error": "not found"}, status=404)
                    return
                index = int(match.group(1))
                if index < 0 or index >= len(outer.music_tracks):
                    self._send_json({"error": "not found"}, status=404)
                    return
                self._send_media_file(outer.music_tracks[index], "audio/wav")

            def _send_sound(self, path):
                match = re.fullmatch(r"/sound/([a-z0-9_]+)\.(mp3|wav|ogg)", path)
                if not match:
                    self._send_json({"error": "not found"}, status=404)
                    return
                key, extension = match.groups()
                track = outer.sound_effects.get(key)
                if not track or track.suffix.lower().lstrip(".") != extension:
                    self._send_json({"error": "not found"}, status=404)
                    return
                content_type = {"mp3": "audio/mpeg", "wav": "audio/wav", "ogg": "audio/ogg"}.get(extension, "application/octet-stream")
                self._send_media_file(track, content_type)

            def _send_voice(self, path):
                match = re.fullmatch(r"/voice/([a-f0-9]{24,64}\.wav)", path)
                if not match or not outer.voice_service:
                    self._send_json({"error": "not found"}, status=404)
                    return
                track = outer.voice_service.voice_clip_path(match.group(1))
                if not track:
                    self._send_json({"error": "not found"}, status=404)
                    return
                self._send_media_file(track, "audio/wav")

            def _send_media_file(self, track, content_type):
                try:
                    size = track.stat().st_size
                    start, end = 0, size - 1
                    status = 200
                    range_header = self.headers.get("Range", "")
                    match_range = re.fullmatch(r"bytes=(\d*)-(\d*)", range_header.strip())
                    if match_range:
                        left, right = match_range.groups()
                        if left == "" and right:
                            suffix = min(size, int(right))
                            start = size - suffix
                        elif left:
                            start = int(left)
                        if right and left:
                            end = min(size - 1, int(right))
                        if start > end or start >= size:
                            self.send_response(416)
                            self.send_header("Content-Range", f"bytes */{size}")
                            self.send_header("Access-Control-Allow-Origin", "*")
                            self.end_headers()
                            return
                        status = 206
                    length = end - start + 1
                    self.send_response(status)
                    self.send_header("Content-Type", content_type)
                    self.send_header("Content-Length", str(length))
                    self.send_header("Cache-Control", "no-store")
                    self.send_header("Accept-Ranges", "bytes")
                    if status == 206:
                        self.send_header("Content-Range", f"bytes {start}-{end}/{size}")
                    self.send_header("Access-Control-Allow-Origin", "*")
                    self.end_headers()
                    with track.open("rb") as handle:
                        handle.seek(start)
                        remaining = length
                        while True:
                            if remaining <= 0:
                                break
                            chunk = handle.read(min(1024 * 256, remaining))
                            if not chunk:
                                break
                            remaining -= len(chunk)
                            self.wfile.write(chunk)
                except (BrokenPipeError, ConnectionResetError, OSError):
                    return

            def log_message(self, _format, *_args):
                return

        self._server = QuietThreadingHTTPServer((self.host, self.port), Handler)
        self._server.daemon_threads = True
        self.port = self._server.server_address[1]
        self._thread = Thread(target=self._server.serve_forever, name="poker-overlay", daemon=True)
        self._thread.start()
        return self

    @property
    def url(self):
        return f"http://{self.host}:{self.port}/overlay"

    def state_snapshot(self):
        state = self.game.state_snapshot()
        self._attach_voice_clips(state)
        return state

    def _attach_voice_clips(self, state):
        service = self.voice_service
        audio = state.setdefault("audio", {})
        if service:
            audio["voice_clips"] = service.snapshot()
        else:
            audio["voice_clips"] = {"schema_version": 1, "enabled": False, "status": "disabled"}
            return

        presentation = state.get("presentation") or {}
        cue = presentation.get("voice_cue") or {}
        if cue.get("enabled") and cue.get("line"):
            cue.update(
                service.prepare_voice_cue(
                    cue,
                    speaker_id="host",
                    speaker_name=cue.get("speaker") or "Night City host",
                    voice="host",
                    kind="host",
                )
            )

        casino = state.get("casino") or {}
        spectacle = casino.get("spectacle_cue") or {}
        if spectacle.get("voice_line"):
            spectacle_cue = {
                "id": f"casino|{casino.get('round_id', 0)}|{spectacle.get('voice_line', '')}",
                "line": spectacle.get("voice_line", ""),
            }
            spectacle.update(
                service.prepare_voice_cue(
                    spectacle_cue,
                    speaker_id="host",
                    speaker_name="Night City host",
                    voice="host",
                    kind="casino_host",
                )
            )

        talk = self._latest_table_talk_voice(state)
        if talk:
            talk.update(
                service.prepare_voice_cue(
                    {"id": talk["id"], "line": talk["line"]},
                    speaker_id=talk["player_id"],
                    speaker_name=talk["speaker"],
                    voice=talk["voice_id"],
                    kind="table_talk",
                )
            )
            presentation["table_talk_voice"] = talk

    def _latest_table_talk_voice(self, state):
        players = state.get("players") or []
        by_id = {str(player.get("id", "")): player for player in players}
        by_name = {str(player.get("name", "")).lower(): player for player in players}
        try:
            recent_events = self.game.events_since(max(0, int(state.get("event_sequence", 0)) - 80))
        except Exception:
            recent_events = []
        for event in reversed(recent_events):
            if event.get("type") != "table_talk":
                continue
            line = str(event.get("message") or "").strip()
            if not line or ":" not in line:
                continue
            speaker, text = line.split(":", 1)
            text = re.sub(r"\s+", " ", text).strip()
            if not text:
                continue
            event_player_id = str(event.get("player_id") or "")
            event_speaker = str(event.get("player") or speaker.strip())
            player = by_id.get(event_player_id) or by_name.get(event_speaker.lower()) or by_name.get(speaker.strip().lower())
            profile = (player or {}).get("profile") or {}
            player_id = (player or {}).get("id") or event_player_id or speaker.strip().lower()
            digest = re.sub(r"[^a-zA-Z0-9]+", "-", text.lower()).strip("-")[:32]
            return {
                "schema_version": 1,
                "enabled": True,
                "id": f"talk|{event.get('id', state.get('event_sequence', 0))}|{player_id}|{digest}",
                "speaker": event_speaker,
                "player_id": player_id,
                "voice_id": profile.get("voice") or player_id,
                "line": text[:160],
                "caption": line[:190],
            }
        for raw in reversed(state.get("commentary") or []):
            line = str(raw or "").strip()
            if ":" not in line or re.search(r"\b(wins?|posts|dealt)\b", line, re.IGNORECASE):
                continue
            speaker, text = line.split(":", 1)
            player = by_name.get(speaker.strip().lower())
            if not player:
                continue
            text = re.sub(r"\s+", " ", text).strip()
            if not text:
                continue
            profile = player.get("profile") or {}
            player_id = player.get("id") or speaker.strip().lower()
            digest = re.sub(r"[^a-zA-Z0-9]+", "-", text.lower()).strip("-")[:32]
            return {
                "schema_version": 1,
                "enabled": True,
                "id": f"talk|{state.get('hand_number', 0)}|{player_id}|{digest}",
                "speaker": player.get("name", speaker.strip()),
                "player_id": player_id,
                "voice_id": profile.get("voice") or player_id,
                "line": text[:160],
                "caption": line[:190],
            }
        return None

    @staticmethod
    def _query_enabled(query, key, default):
        if key not in query:
            return bool(default)
        value = (query.get(key) or [""])[-1].strip().lower()
        return value not in {"0", "false", "off", "no", "muted"}

    def _discover_music_tracks(self):
        if not self.music_dir.exists() or not self.music_dir.is_dir():
            return ()
        return tuple(
            sorted(
                (
                    path
                    for path in self.music_dir.iterdir()
                    if path.is_file() and path.suffix.lower() == ".wav"
                ),
                key=lambda path: path.name.lower(),
            )
        )

    def _discover_sound_effects(self):
        if not self.sound_effects_dir.exists() or not self.sound_effects_dir.is_dir():
            return {}
        effects = {}
        for path in sorted(self.sound_effects_dir.iterdir(), key=lambda item: item.name.lower()):
            if not path.is_file() or path.suffix.lower() not in {".mp3", ".wav", ".ogg"}:
                continue
            normalized = path.stem.lower().replace("-", "_").replace(" ", "_")
            if "card" in normalized and "flip" in normalized:
                effects["card_flip"] = path
        return effects

    def sound_effect_urls(self):
        return {
            key: f"/sound/{key}{path.suffix.lower()}"
            for key, path in self.sound_effects.items()
        }

    def stream_info(self):
        """Return copy-safe public metadata without cards, prompts, or local paths."""
        state = self.game.state_snapshot()
        tournament = state.get("tournament") or {}
        variety = state.get("variety") or {}
        casino = state.get("casino") or {}
        casino_block = casino.get("program_block") or {}
        if state["mode"] == "tournament":
            program = variety.get("title") or f"Sit & Go {tournament.get('number', 1)} · Level {tournament.get('level', 1)}"
            summary = f"{program}: tournament {tournament.get('number', 1)}, hand {tournament.get('hand', 0)}. All chips and records are fictional."
        else:
            program = variety.get("title") or "AI Poker League Exhibition Table"
            summary = f"{program}: {state['blinds']['small']}/{state['blinds']['big']} simulated-chip exhibition game."
        current_room = casino_block.get("title") or program
        if casino.get("active_game") and casino.get("active_game") != "poker":
            summary = f"{current_room}: AI-only {casino.get('active_game')} room with fictional bankroll drama. No viewer inputs affect outcomes."
        return {
            "schema_version": 1,
            "title": "Night City AI Gambling Den | Autonomous AI Casino | Simulation Only | No Real Money",
            "description": "Autonomous local AI players rotate through poker and AI-only casino rooms with fictional chips and fictional bankrolls. Entertainment software only; no real-world wagering or prizes.",
            "disclaimer": "Simulation only · fictional chips · no real money · no prizes",
            "current_program": current_room,
            "casino_program": {
                "active_game": casino.get("active_game", "poker"),
                "block_title": current_room,
                "hook": casino_block.get("viewer_hook"),
                "responsible_label": casino.get("responsible_label"),
            },
            "season_summary": summary,
            "players": [
                {"id": player["id"], "name": player["name"], "bio": player["profile"]["persona"]}
                for player in state["players"]
            ],
            "tech_stack": "Local-first Python rules engine, Ollama AI players, Qt control room, and an OBS browser overlay.",
        }

    def close(self):
        self._closing = True
        if self.voice_service:
            self.voice_service.close()
        if self._server:
            self._server.shutdown()
            self._server.server_close()
        if self._thread:
            self._thread.join(timeout=2)
